---@class LFightPlayContinue
local LFightPlayContinue = LxClass("LFightPlayContinue", nil)

function LFightPlayContinue:LFightPlayContinue()

end

function LFightPlayContinue:Start(combatType, combatData)
    self._combatData = combatData
    self._serverId = combatData.serverId
    self._combatType = combatType
    self._isNew = combatData.isNew
    self._curIndex = 0
    local isBackGround = combatData.isBattleToBackground

    if combatType == LCombatTypeConst.COMBAT_BATTLE_VIDEO then
        gModelBattle:RecordVideoBattleLife(LCombatTypeConst.COMBAT_BATTLE_VIDEO, true)
    end

    self:NextBattle(isBackGround)
end

function LFightPlayContinue:NextBattle(isBackGround)
    if self._skipAll then
        self:OnEnd()
        return
    end

    if not self._combatData then return end

    self._isBackGround = isBackGround

    if not self._curIndex then
        self._curIndex = 0
    end
    
    self._curIndex = self._curIndex + 1
    local reportId = self._combatData.reportList[self._curIndex]

    if not reportId then
        self:OnEnd()
        return
    end

    printInfoN("reportId " .. reportId)

    self:StartFromReportId(reportId)
end

function LFightPlayContinue:StartFromReportId(reportId)
    self._curReportId = reportId
    local serverId = self._serverId
    if not serverId then
        serverId = gLGameLogin:GetActualServerId()
    end

    local reportInfo = {
        reportId = reportId,
        combatType = self._combatType,
        serverId = serverId,
        callback = function(reportTable)
            self:DoRespWebReport(reportTable)
        end
    }

    if not reportInfo.serverId then
        printErrorN(string.format("report serverId is nil"))
        return
    end

    local getter = self._getter
    if getter then
        getter:Destroy()
    end
    getter = LFightReportGetter:New()
    self._getter = getter

    self:StartTimeoutTimer()

    getter:Start(reportInfo)


end

function LFightPlayContinue:DoRespWebReport(reportTable)

    self._reqTime = nil

    local combatType = self._combatType
    local reportId = self._curReportId

    local extraData = {
        combatType = self._combatData.combatType,
        skip = self._combatData.skipType,
        winnerNumber = self._combatData.winnerNumber,
        battleEndfun = function(isChangeBot, isBackGround)
            self:NextBattle(isBackGround)
        end,
        isBattleToBackground = self._isBackGround,
        battlePlayCtrl = self,
        index = self._curIndex,
        isNew = self._isNew,
    }
    gLFightManager:StartBattle(reportId, combatType, extraData, reportTable)
end

function LFightPlayContinue:SkipAll()
    self._skipAll = true
end

function LFightPlayContinue:OnEnd()
    if self._combatData then
        local battleEndFun = self._combatData.battleEndfun
        if battleEndFun then
            battleEndFun()
        end
    end

    self:Destroy()
end

function LFightPlayContinue:CheckCanReplace()
    if self:IsDestroy() then
        return true
    end

    if self._timeOut then
        return true
    end

    return false
end

function LFightPlayContinue:IsDestroy()
    return self._isDestroy
end

function LFightPlayContinue:Destroy()
    if self._getter then
        self._getter:Destroy()
    end

    self._getter = nil

    if self._combatType == LCombatTypeConst.COMBAT_BATTLE_VIDEO then
        gModelBattle:RecordVideoBattleLife(LCombatTypeConst.COMBAT_BATTLE_VIDEO, false)
    end

    table.removeall(self)
    self._isDestroy = true
end

function LFightPlayContinue:StartTimeoutTimer()
    if not self._timer then
        self._timer = LxTimer:New()
    end
    self._timeOut = false
    local key = "timeoutCheck"
    self._timer:TimerRemoveByKey(key)
    self._timer:TimerCreate(key, function(...)
        self._timeOut = true
    end, 3, true, 1)
end

return LFightPlayContinue